-- --------------------------------------------------------

DROP TABLE IF EXISTS `assignment_feedbacks`;

CREATE TABLE `assignment_feedbacks` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `assignment_group_learner_id` int(11) unsigned NOT NULL,
  `user_id` int(11) unsigned NOT NULL,
  `filename` varchar(255) NOT NULL DEFAULT '',
  `is_admin` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `user_id` (`user_id`),
  KEY `assignment_group_learner_id` (`assignment_group_learner_id`),
  CONSTRAINT `assignment_feedbacks_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `assignment_feedbacks_ibfk_3` FOREIGN KEY (`assignment_group_learner_id`) REFERENCES `assignment_group_learners` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `assignment_group_learners`;

CREATE TABLE `assignment_group_learners` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `assignment_group_id` int(11) unsigned NOT NULL,
  `user_id` int(11) unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `user_id` (`user_id`),
  KEY `assignment_group_id` (`assignment_group_id`),
  CONSTRAINT `assignment_group_learners_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `assignment_group_learners_ibfk_3` FOREIGN KEY (`assignment_group_id`) REFERENCES `assignment_groups` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `assignment_groups`;

CREATE TABLE `assignment_groups` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `assignment_id` int(11) unsigned NOT NULL,
  `title` varchar(255) NOT NULL DEFAULT '',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `assignment_id` (`assignment_id`),
  CONSTRAINT `assignment_groups_ibfk_1` FOREIGN KEY (`assignment_id`) REFERENCES `assignments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `assignment_manuscripts`;

CREATE TABLE `assignment_manuscripts` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `assignment_id` int(11) unsigned NOT NULL,
  `user_id` int(11) unsigned NOT NULL,
  `filename` varchar(255) NOT NULL DEFAULT '',
