-- --------------------------------------------------------

DROP TABLE IF EXISTS `manuscripts`;

CREATE TABLE `manuscripts` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `coursetaken_id` int(10) unsigned NOT NULL,
  `filename` longtext NOT NULL,
  `word_count` int(11) NOT NULL,
  `grade` double(11,1) DEFAULT NULL,
  `feedback_user_id` int(11) unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `course_id` (`coursetaken_id`),
  KEY `feedback_user_id` (`feedback_user_id`),
  CONSTRAINT `manuscripts_ibfk_11` FOREIGN KEY (`coursetaken_id`) REFERENCES `courses_taken` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `manuscripts_ibfk_12` FOREIGN KEY (`feedback_user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=64 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `migrations`;

CREATE TABLE `migrations` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `migration` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `batch` int(11) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `package_courses`;

CREATE TABLE `package_courses` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `package_id` int(11) unsigned NOT NULL,
  `included_package_id` int(11) unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `package_shop_manuscripts`;

CREATE TABLE `package_shop_manuscripts` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `package_id` int(11) unsigned NOT NULL,
  `shop_manuscript_id` int(11) unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `package_id` (`package_id`),
  KEY `shop_manuscript_id` (`shop_manuscript_id`),
  CONSTRAINT `package_shop_manuscripts_ibfk_1` FOREIGN KEY (`package_id`) REFERENCES `packages` (`id`) ON DELETE CASCADE,
  CONSTRAINT `package_shop_manuscripts_ibfk_2` FOREIGN KEY (`shop_manuscript_id`) REFERENCES `shop_manuscripts` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=35 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `package_workshops`;

CREATE TABLE `package_workshops` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `package_id` int(11) unsigned NOT NULL,
  `workshop_id` int(11) unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `package_id` (`package_id`),
  KEY `workshop_id` (`workshop_id`),
  CONSTRAINT `package_workshops_ibfk_1` FOREIGN KEY (`package_id`) REFERENCES `packages` (`id`) ON DELETE CASCADE,
  CONSTRAINT `package_workshops_ibfk_2` FOREIGN KEY (`workshop_id`) REFERENCES `workshops` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `packages`;

CREATE TABLE `packages` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `course_id` int(10) unsigned NOT NULL,
  `variation` longtext NOT NULL,
  `description` longtext NOT NULL,
  `manuscripts_count` int(11) NOT NULL DEFAULT '0',
  `full_payment_price` decimal(11,2) NOT NULL,
  `months_3_price` decimal(11,2) NOT NULL,
  `months_6_price` decimal(11,2) NOT NULL,
  `full_price_product` varchar(255) NOT NULL DEFAULT '',
  `months_3_product` varchar(255) NOT NULL DEFAULT '',
  `months_6_product` varchar(255) NOT NULL DEFAULT '',
  `full_price_due_date` int(11) NOT NULL,
  `months_3_due_date` int(11) NOT NULL,
  `months_6_due_date` int(11) NOT NULL,
  `workshops` int(11) DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `course_id` (`course_id`),
  CONSTRAINT `packages_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=30 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `password_resets`;

CREATE TABLE `password_resets` (
  `email` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `token` varchar(255) COLLATE utf8_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  KEY `password_resets_email_index` (`email`),
  KEY `password_resets_token_index` (`token`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `payment_modes`;

CREATE TABLE `payment_modes` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `mode` varchar(255) NOT NULL DEFAULT '',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `payment_plans`;

CREATE TABLE `payment_plans` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `plan` varchar(255) NOT NULL DEFAULT '',
  `division` int(11) NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `settings`;

CREATE TABLE `settings` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `setting_name` varchar(100) NOT NULL DEFAULT '',
  `setting_value` longtext,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `shop_manuscript_comments`;

CREATE TABLE `shop_manuscript_comments` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `shop_manuscript_taken_id` int(10) unsigned NOT NULL,
  `user_id` int(10) unsigned NOT NULL,
  `comment` longtext NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `shop_manuscript_taken_id` (`shop_manuscript_taken_id`),
  KEY `user_id` (`user_id`),
  CONSTRAINT `shop_manuscript_comments_ibfk_1` FOREIGN KEY (`shop_manuscript_taken_id`) REFERENCES `shop_manuscripts_taken` (`id`) ON DELETE CASCADE,
  CONSTRAINT `shop_manuscript_comments_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `shop_manuscript_taken_feedbacks`;

CREATE TABLE `shop_manuscript_taken_feedbacks` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `shop_manuscript_taken_id` int(11) unsigned NOT NULL,
  `filename` longtext NOT NULL,
  `notes` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `manuscript_id` (`shop_manuscript_taken_id`),
  CONSTRAINT `shop_manuscript_taken_feedbacks_ibfk_1` FOREIGN KEY (`shop_manuscript_taken_id`) REFERENCES `shop_manuscripts_taken` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=26 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `shop_manuscripts`;

CREATE TABLE `shop_manuscripts` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `title` varchar(100) NOT NULL DEFAULT '',
  `description` longtext,
  `max_words` int(11) NOT NULL,
  `price` decimal(11,2) NOT NULL,
  `split_payment_price` decimal(11,2) NOT NULL,
  `fiken_product` varchar(255) NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `shop_manuscripts_taken`;

CREATE TABLE `shop_manuscripts_taken` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` int(11) unsigned NOT NULL,
  `shop_manuscript_id` int(11) unsigned NOT NULL,
  `file` longtext,
  `words` int(11) DEFAULT NULL,
  `is_active` tinyint(4) NOT NULL DEFAULT '0',
  `feedback_user_id` int(11) unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `user_id` (`user_id`),
  KEY `package_id` (`shop_manuscript_id`),
  KEY `feedback_user_id` (`feedback_user_id`),
  CONSTRAINT `shop_manuscripts_taken_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `shop_manuscripts_taken_ibfk_2` FOREIGN KEY (`shop_manuscript_id`) REFERENCES `shop_manuscripts` (`id`) ON DELETE CASCADE,
  CONSTRAINT `shop_manuscripts_taken_ibfk_3` FOREIGN KEY (`feedback_user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=76 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `similar_courses`;

CREATE TABLE `similar_courses` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `course_id` int(10) unsigned NOT NULL,
  `similar_course_id` int(10) unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `course_id` (`course_id`),
  KEY `similar_course_id` (`similar_course_id`),
  CONSTRAINT `similar_courses_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE,
  CONSTRAINT `similar_courses_ibfk_2` FOREIGN KEY (`similar_course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=latin1;



-- --------------------------------------------------------

DROP TABLE IF EXISTS `transactions`;

CREATE TABLE `transactions` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `invoice_id` int(10) unsigned NOT NULL,
  `mode` varchar(100) NOT NULL DEFAULT '',
  `mode_transaction` varchar(100) DEFAULT NULL,
  `amount` decimal(11,2) NOT NULL,
