INSERT INTO `settings` (`id`, `setting_name`, `setting_value`) VALUES
(2,	'welcome_email',	'Hei og velkommen til Forfatterskolen!\r\n\r\nVi er sÃ¥ glade for Ã¥ ha deg med! Vi i Forfatterskolen er selv forfattere, og hÃ¥per at vi gjennom vÃ¥re skrivekurs og erfaringer kan bli den redaktÃ¸ren, mentoren og heiagjengen som hjelper deg med Ã¥ lykkes med din skrivedrÃ¸m ? uansett nivÃ¥ og sjanger. \r\n\r\nLykke til med skrivingen og husk at du nÃ¥r som helst kan ta kontakt hvis du trenger noe fra oss! \r\n\r\nAlt godt,\r\nKristine');
INSERT INTO `shop_manuscript_comments` (`id`, `shop_manuscript_taken_id`, `user_id`, `comment`, `created_at`, `updated_at`) VALUES
(1,	42,	2,	'test',	'2017-08-30 06:54:13',	'2017-08-30 06:54:13'),
(2,	42,	10,	'Lorem',	'2017-08-30 06:55:23',	'2017-08-30 06:55:23'),
(3,	49,	1,	'Fortellingen er basert pÃ¥ hendelser som foregikk i 1964. Totto, en gutt pÃ¥ 12 Ã¥r, fÃ¥r plutselig livet snudd opp ned. Den ene dagen scorer han vinnermÃ¥let for Vormedal FK, den neste dagen kommer han inn pÃ¥ Haugesund Sykehus med en alvorlig diagnose. Derfra blir han sendt til Radiumhospitalet hvor han skrives inn som pasient nr. 27. Han blir snart plassert i  Â«dÃ¸dsbunkenÂ» til professor Poppe. Faren Otto kjemper mot dÃ¸dsprognosen, og allierer seg med  dr. Lorenz Nitter og med andre Â«dissentereÂ» for Ã¥ redde sÃ¸nnen. Det blir en intens kamp bÃ¥de mot faglige autoriteter, mot tiden og mot sykdommen. Otto mÃ¥ mobilisere alt han har av mot,  standhaftighet og kjÃ¦rlighet til sÃ¸nnen for Ã¥ redde ham. Dette er ogsÃ¥ en historie om hvordan en hÃ¸ysensitiv gutt opplever mÃ¸tet med sykehusvesenet i en tid hvor ingenting var spesielt tilrettelagt for barn.  Jeg har ikke gitt ut bÃ¸ker fÃ¸r, og selv om jeg er en godt voksen person, har jeg mye Ã¥ lÃ¦re i forhold til det rent hÃ¥ndverksmessige.  Tidligere versjoner av manuset er lest av manuskonsulenter, og jeg har prÃ¸vd Ã¥ innarbeide tips fra dem i dette. Jeg har med rette eller urette ambisjoner om Ã¥ fÃ¥ manuset utgitt pÃ¥ forlag, men er ikke fremmed for Ã¥ publisere selv. Aller fÃ¸rst vil jeg uansett ha en sjekk av manuset, i den foreliggende versjon, fra kompetent hold',	'2017-08-30 15:09:49',	'2017-08-30 15:09:49');
